    const initialState: InternalState = {
      items: new Map(),
      reservations: new Map(),
      nextReservationId: 1,
    }
    try {
      this.stateRef = Effect.runSync(Ref.make(initialState))
    } catch (e) {
      throw new Error(`Failed to initialize inventory system: ${String(e)}`)
    }
  }

